@pytest.mark.ui
@pytest.mark.e2e
def test_registration_tab_order_works(authenticated_page: Page):
    """Tab key navigates through form fields in logical order."""
    page = authenticated_page
    import os
    page.goto(os.getenv("TARGET_PAGE_URL", "/register"))
    page.wait_for_load_state("networkidle")
    first_input = page.query_selector("input:not([type=hidden])")
    if first_input:
        first_input.click()
        page.keyboard.press("Tab")
        # Should move focus to next field without error
        focused = page.evaluate("() => document.activeElement?.tagName")
        assert focused in ["INPUT", "SELECT", "TEXTAREA", "BUTTON"]
